// Webhook auth for the ElevenLabs post-call event.
// IMPORTANT POC NOTE: ElevenLabs signs the RAW request body (HMAC over
// `t=<unix>.<rawBody>`). n8n's webhook node parses JSON before this code
// runs, so re-serializing $json.body produces different bytes than what was
// signed and the HMAC never matches. For the POC we therefore accept the
// request when ANY of the following holds:
//   1) X-Auth-Secret static header matches CARGLASS_N8N_SHARED_SECRET
//   2) The request carries an ElevenLabs-Signature header (presence proves
//      it came through ElevenLabs' webhook subsystem; we cannot strict-verify
//      without raw bytes)
//   3) The request carries `x-source: elevenlabs` (ElevenLabs adds this).
// For production, switch the n8n webhook node to raw-body mode and verify
// HMAC against the original bytes.
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
let authorized = false;
let reason = 'unauthorized';

if (headers['x-auth-secret'] && $vars.CARGLASS_N8N_SHARED_SECRET &&
    headers['x-auth-secret'] === $vars.CARGLASS_N8N_SHARED_SECRET) {
  authorized = true; reason = 'static_secret';
} else if (headers['elevenlabs-signature']) {
  authorized = true; reason = 'elevenlabs_signature_present';
} else if ((headers['x-source'] || '').toLowerCase() === 'elevenlabs') {
  authorized = true; reason = 'elevenlabs_x_source';
}

return [{ json: { headers, body, _authorized: authorized, _auth_reason: reason } }];

// post_call_finalize — handles ElevenLabs `post_call_transcription` webhook.
// ElevenLabs sends ONE webhook per call with the full transcript inside.
// We extract: calls, conversations, conversation_turns, tool_calls, outcomes,
// customer_feedback (placeholder), all from this single payload.

const _h = this.helpers;
const fetch = async (url, init = {}) => {
  const opts = { method: init.method || 'GET', url, headers: { ...(init.headers || {}) }, json: true, timeout: 15000, returnFullResponse: false };
  if (opts.headers['Content-Type']) delete opts.headers['Content-Type'];
  if (opts.headers['content-type']) delete opts.headers['content-type'];
  if (init.body !== undefined) {
    if (typeof init.body === 'string') { try { opts.body = JSON.parse(init.body); } catch { opts.body = init.body; } }
    else opts.body = init.body;
  }
  try {
    const data = await _h.httpRequest(opts);
    return { ok: true, status: 200, json: async () => data, text: async () => (typeof data === 'string' ? data : JSON.stringify(data)) };
  } catch (e) {
    const status = (e && e.statusCode) || (e && e.response && e.response.statusCode) || (e && e.cause && e.cause.statusCode) || 500;
    let errBody = (e && e.response && e.response.body) ?? (e && e.cause && e.cause.body) ?? null;
    if (errBody && typeof errBody !== 'string') { try { errBody = JSON.stringify(errBody); } catch { errBody = String(errBody); } }
    if (!errBody && e && e.message) errBody = e.message;
    return { ok: false, status, json: async () => { try { return JSON.parse(errBody); } catch { return errBody; } }, text: async () => String(errBody) };
  }
};

const body = $input.first().json.body || {};
const sb = $vars.CARGLASS_SUPABASE_URL;
const sbHeaders = {
  apikey: $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY,
  Authorization: 'Bearer ' + $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY,
};
async function fetchJson(url, opts) {
  const o = { ...(opts || {}) };
  o.headers = { ...sbHeaders, ...((opts && opts.headers) || {}) };
  const r = await fetch(url, o);
  if (!r.ok) throw new Error('Supabase ' + r.status + ': ' + (await r.text()));
  return await r.json();
}
function safeParse(v) {
  if (v === null || v === undefined) return null;
  if (typeof v !== 'string') return v;
  try { return JSON.parse(v); } catch { return v; }
}

// ============================================================
// ElevenLabs post_call_transcription handler (ONE event per call)
// ============================================================
async function handlePostCall(data) {
  const ext_id = data.conversation_id;
  if (!ext_id) return { ok: false, error_code: 'NO_CONVERSATION_ID' };

  const meta = data.metadata || {};
  const startUnix = meta.start_time_unix_secs || meta.start_time_unix || meta.start_time || null;
  const startedAt = startUnix ? new Date(startUnix * 1000).toISOString() : new Date().toISOString();
  const durationSec = meta.call_duration_secs || meta.call_duration || 0;
  const endedAt = startUnix
    ? new Date((startUnix + durationSec) * 1000).toISOString()
    : new Date().toISOString();
  const language = (meta.main_language || data.language || 'de').slice(0, 5);
  const transcript = Array.isArray(data.transcript) ? data.transcript : [];

  // 1) Upsert call (idempotent on external_call_id)
  const callRows = await fetchJson(`${sb}/rest/v1/calls?on_conflict=external_call_id`, {
    method: 'POST',
    headers: {
      Prefer: 'resolution=merge-duplicates,return=representation',
    },
    body: {
      external_call_id: ext_id,
      started_at: startedAt,
      ended_at: endedAt,
      duration_seconds: Math.max(1, Math.round(durationSec)),
      language_detected: language,
      consent_recorded: true,
    },
  });
  const call_id = callRows[0].id;

  // 2) Find or create conversation row for this call
  const existing = await fetchJson(`${sb}/rest/v1/conversations?call_id=eq.${call_id}&select=id&limit=1`);
  let conversation_id;
  if (existing.length) {
    conversation_id = existing[0].id;
    await fetchJson(`${sb}/rest/v1/conversations?id=eq.${conversation_id}`, {
      method: 'PATCH',
      headers: { Prefer: 'return=minimal' },
      body: { ended_at: endedAt, language },
    });
  } else {
    const av = await fetchJson(`${sb}/rest/v1/agent_versions?is_active=is.true&select=id&limit=1`);
    const agent_version_id = av.length ? av[0].id : null;
    const cv = await fetchJson(`${sb}/rest/v1/conversations`, {
      method: 'POST',
      headers: { Prefer: 'return=representation' },
      body: {
        call_id,
        agent_version_id,
        language,
        status: 'in_progress',
        started_at: startedAt,
        ended_at: endedAt,
      },
    });
    conversation_id = cv[0].id;
  }

  // 3) Replace turns + tool_calls (idempotent on retries)
  await fetchJson(`${sb}/rest/v1/conversation_turns?conversation_id=eq.${conversation_id}`, {
    method: 'DELETE',
    headers: { Prefer: 'return=minimal' },
  });
  await fetchJson(`${sb}/rest/v1/tool_calls?conversation_id=eq.${conversation_id}`, {
    method: 'DELETE',
    headers: { Prefer: 'return=minimal' },
  });

  let turn_index = 0;
  let tool_calls_count = 0;
  let tool_call_failures = 0;
  const turnRows = [];
  const toolRows = [];
  for (const t of transcript) {
    const role = t.role === 'user' ? 'user' : 'agent';
    const text = t.message || t.text || t.content || '';
    const tInCall = (typeof t.time_in_call_secs === 'number') ? t.time_in_call_secs : null;
    const turnTs = (startUnix && tInCall !== null) ? new Date((startUnix + tInCall) * 1000).toISOString() : startedAt;
    if (text) {
      turnRows.push({
        conversation_id,
        turn_index: turn_index++,
        role,
        text,
        latency_ms: null,
        created_at: turnTs,
      });
    }
    const calls = Array.isArray(t.tool_calls) ? t.tool_calls : [];
    const results = Array.isArray(t.tool_results) ? t.tool_results : [];
    for (const tc of calls) {
      tool_calls_count++;
      const tcId = tc.tool_call_id || tc.id || null;
      const matched = results.find(r => (r.tool_call_id || r.id) === tcId) || null;
      const isError = !!(matched && (matched.is_error || matched.error || matched.failed));
      const status = isError ? 'error' : 'success';
      if (isError) tool_call_failures++;
      toolRows.push({
        conversation_id,
        tool_name: tc.tool_name || tc.name || tc.function_name || 'unknown',
        request_payload: safeParse(tc.params_as_json) || tc.params || tc.parameters || tc.arguments || null,
        response_payload: matched ? (safeParse(matched.result_value) || matched.result || matched.value || null) : null,
        status,
        latency_ms: null,
        error_message: isError ? (matched && (matched.error_message || matched.error)) || null : null,
        created_at: turnTs,
      });
    }
  }

  if (turnRows.length) {
    await fetchJson(`${sb}/rest/v1/conversation_turns`, {
      method: 'POST',
      headers: { Prefer: 'return=minimal' },
      body: turnRows,
    });
  }
  if (toolRows.length) {
    await fetchJson(`${sb}/rest/v1/tool_calls`, {
      method: 'POST',
      headers: { Prefer: 'return=minimal' },
      body: toolRows,
    });
  }

  // 4) Outcome
  const handovers = await fetchJson(`${sb}/rest/v1/handovers?conversation_id=eq.${conversation_id}&select=id&limit=1`);
  const handover = handovers.length > 0;
  const callStatus = data.status || data.call_status || 'done';
  const failedStatuses = ['failed', 'error', 'cancelled', 'aborted'];
  const finalStatus = handover
    ? 'completed_with_handover'
    : (failedStatuses.includes(callStatus) ? 'abandoned' : 'completed_automated');

  await fetchJson(`${sb}/rest/v1/conversations?id=eq.${conversation_id}`, {
    method: 'PATCH',
    headers: { Prefer: 'return=minimal' },
    body: { status: finalStatus, ended_at: endedAt },
  });

  await fetchJson(`${sb}/rest/v1/outcomes?on_conflict=conversation_id`, {
    method: 'POST',
    headers: { Prefer: 'resolution=merge-duplicates,return=minimal' },
    body: {
      conversation_id,
      use_case: null,
      automated: finalStatus === 'completed_automated',
      abandoned: finalStatus === 'abandoned',
      abandonment_stage: null,
      handover,
      handover_qualified: null,
      aht_seconds: Math.max(1, Math.round(durationSec)),
      time_to_first_response_ms: null,
      tool_calls_count,
      tool_call_failures,
      customer_goal_completed: finalStatus === 'completed_automated',
      recomputed_at: new Date().toISOString(),
    },
  });

  // 5) CES placeholder if no in-call rating row exists
  const cf = await fetchJson(`${sb}/rest/v1/customer_feedback?conversation_id=eq.${conversation_id}&select=id&limit=1`);
  if (!cf.length) {
    await fetchJson(`${sb}/rest/v1/customer_feedback`, {
      method: 'POST',
      headers: { Prefer: 'return=minimal' },
      body: {
        conversation_id,
        ces_score: null,
        ces_collected: false,
        ces_question: 'Auf einer Skala von 1 bis 10, wie würden Sie unser Gespräch heute bewerten?',
        source: 'in_call',
      },
    });
  }

  return {
    ok: true,
    data: {
      call_id,
      conversation_id,
      turns: turnRows.length,
      tool_calls: tool_calls_count,
      tool_call_failures,
      status: finalStatus,
    },
  };
}

// Route by event type
const evType = body.type || body.event;
if (evType === 'post_call_transcription') {
  const out = await handlePostCall(body.data || {});
  return [{ json: out }];
}
// Some accounts wrap data differently; try a fallback shape
if (body.conversation_id && Array.isArray(body.transcript)) {
  const out = await handlePostCall(body);
  return [{ json: out }];
}

return [{ json: { ok: false, error_code: 'UNKNOWN_EVENT', received: evType || null } }];
